import numpy as np
from sklearn.ensemble import VotingClassifier
from sklearn.base import BaseEstimator, ClassifierMixin

class EnsembleClassifier(BaseEstimator, ClassifierMixin):
    def __init__(self, estimators, weights=None):
        self.estimators = estimators
        self.weights = weights

    def fit(self, X, y):
        for estimator in self.estimators:
            estimator.fit(X, y)
        return self

    def predict(self, X):
        predictions = [estimator.predict(X) for estimator in self.estimators]
        predictions = np.array(predictions)
        if self.weights is None:
            votes = np.apply_along_axis(lambda x: np.argmax(np.bincount(x)), axis=0, arr=predictions)
        else:
            votes = np.apply_along_axis(lambda x: np.argmax(np.dot(np.bincount(x), self.weights)), axis=0, arr=predictions)
        return votes

    def predict_proba(self, X):
        probas = [estimator.predict_proba(X) for estimator in self.estimators]
        probas = np.array(probas)
        if self.weights is None:
            avg_proba = np.mean(probas, axis=0)
        else:
            avg_proba = np.average(probas, axis=0, weights=self.weights)
        return avg_proba

