import numpy as np

def ensemble_classification(nn_predictions, nn_accuracies):
    ensemble_prediction = np.zeros(nn_predictions.shape[1])
    for i in range(nn_predictions.shape[1]):
        class_votes = nn_predictions[:, i]
        class_weights = nn_accuracies
        ensemble_prediction[i] = np.sum(class_votes * class_weights) / np.sum(class_weights)
    return np.argmax(ensemble_prediction)

def calculate_ensemble_accuracy(true_labels, ensemble_predictions):
    correct_predictions = 0
    for i in range(len(true_labels)):
        if true_labels[i] == ensemble_predictions[i]:
            correct_predictions += 1
    return correct_predictions / len(true_labels)

# Example usage
true_labels = [0, 1, 2, 1, 0]
nn_predictions = np.array([[0.6, 0.2, 0.2], [0.1, 0.8, 0.1], [0.3, 0.1, 0.6], [0.2, 0.7, 0.1], [0.7, 0.2, 0.1]])
nn_accuracies = [0.85, 0.90, 0.80]

ensemble_prediction = ensemble_classification(nn_predictions, nn_accuracies)
ensemble_accuracy = calculate_ensemble_accuracy(true_labels, [ensemble_prediction])

print(f"Ensemble classification: {ensemble_prediction}")
print(f"Ensemble accuracy: {ensemble_accuracy:.2f}")

