import numpy as np
from sklearn.ensemble import VotingClassifier
from sklearn.metrics import accuracy_score

def ensemble_prediction(predictions, weights=None):
    if weights is None:
        weights = [1/len(predictions)] * len(predictions)
    ensemble_pred = np.sum([w * p for w, p in zip(weights, predictions)], axis=0)
    return np.argmax(ensemble_pred, axis=1)

def get_confidence_score(ensemble_pred, true_labels):
    accuracy = accuracy_score(true_labels, ensemble_pred)
    return accuracy

def main(neural_net_preds, true_labels):
    ensemble_pred = ensemble_prediction(neural_net_preds)
    confidence_score = get_confidence_score(ensemble_pred, true_labels)
    return ensemble_pred, confidence_score
